    "long_text": "<div class=\"pz-top\">\r\n<div class=\"pz-top-right\"></div>\r\n<div class=\"pz-top-center\"></div>\r\n<div class=\"pz-top-left\"></div>\r\n</div>\r\n\r\n\t\t\t\r\n\t\t\t\r\n\t\t\t<div id=\"post_message_51398\" class=\"pz-post-content\">\n<span><div style=\"text-align: center;\"><span><font><font color=\"#CC0000\">- 26 -</font><font color=\"#0000ff\"><br>\r\n</font><font color=\"#000080\">الإمام ناصر محمد اليماني<br>\r\n01 - 04 - 1430 هـ<br>\r\n28 - 03 - 2009 مـ<br>\r\n11:32 مساءً<br>\r\nــــــــــــــــــــ<br>\r\n</font><font color=\"#0000ff\"><br>\r\n<br>\r\n</font><font color=\"#800080\">{<u>اللَّهُ يَجْتَبِي إِلَيْهِ مَن يَشَاءُ وَيَهْدِي إِلَيْهِ مَن يُنِيبُ</u>} ..</font><font color=\"#0000ff\"><br>\r\n<br>\r\n</font><font color=\"#0000cd\">بسم الله الرحمن الرحيم </font><font color=\"#008000\">{ٱللَّهُ يَجْتَبِىٓ إِلَيْهِ مَن يَشَآءُ وَيَهْدِىٓ إِلَيْهِ مَن يُنِيبُ}</font><font color=\"#0000cd\"> صدق الله العظيم [الشورى:13].<br>\r\n<br>\r\nوقال الله تعالى: </font><font color=\"#008000\">{وَمَا كَانَ ٱللَّهُ لِيُضِلَّ قَوْمَۢا بَعْدَ إِذْ هَدَىٰهُمْ حَتَّىٰ يُبَيِّنَ لَهُم مَّا يَتَّقُونَ ۚ}</font><font color=\"#0000cd\"> صدق الله العظيم [التوبة:115].<br>\r\n<br>\r\nوقال الله تعالى: </font><font><font color=\"#008000\">{</font></font><font color=\"#008000\">۞ قُلْ يَٰعِبَادِىَ ٱلَّذِينَ أَسْرَفُوا۟ عَلَىٰٓ أَنفُسِهِمْ لَا تَقْنَطُوا۟ مِن رَّحْمَةِ ٱللَّهِ ۚ إِنَّ ٱللَّهَ يَغْفِرُ ٱلذُّنُوبَ جَمِيعًا ۚ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ </font><font color=\"#008000\">﴿</font><font color=\"#008000\">٥٣</font><font color=\"#008000\">﴾</font><font color=\"#008000\">وَأَنِيبُوٓا۟ إِلَىٰ رَبِّكُمْ وَأَسْلِمُوا۟ لَهُۥ مِن قَبْلِ أَن يَأْتِيَكُمُ ٱلْعَذَابُ ثُمَّ لَا تُنصَرُونَ </font><font color=\"#008000\">﴿</font><font color=\"#008000\">٥٤</font><font color=\"#008000\">﴾</font><font color=\"#008000\">وَٱتَّبِعُوٓا۟ أَحْسَنَ مَآ أُنزِلَ إِلَيْكُم مِّن رَّبِّكُم مِّن قَبْلِ أَن يَأْتِيَكُمُ ٱلْعَذَابُ بَغْتَةً وَأَنتُمْ لَا تَشْعُرُونَ </font><font color=\"#008000\">﴿</font><font color=\"#008000\">٥٥</font><font color=\"#008000\">﴾</font><font color=\"#008000\">أَن تَقُولَ نَفْسٌ يَٰحَسْرَتَىٰ عَلَىٰ مَا فَرَّطتُ فِى جَنۢبِ ٱللَّهِ وَإِن كُنتُ لَمِنَ ٱلسَّٰخِرِينَ </font><font color=\"#008000\">﴿</font><font color=\"#008000\">٥٦</font><font color=\"#008000\">﴾</font><font color=\"#008000\">أَوْ تَقُولَ لَوْ أَنَّ ٱللَّهَ هَدَىٰنِى لَكُنتُ مِنَ ٱلْمُتَّقِينَ </font><font color=\"#008000\">﴿</font><font color=\"#008000\">٥٧</font><font color=\"#008000\">﴾</font><font color=\"#008000\">أَوْ تَقُولَ حِينَ تَرَى ٱلْعَذَابَ لَوْ أَنَّ لِى كَرَّةً فَأَكُونَ مِنَ ٱلْمُحْسِنِينَ </font><font color=\"#008000\">﴿</font><font color=\"#008000\">٥٨</font><font color=\"#008000\">﴾</font><font color=\"#008000\"> بَلَىٰ قَدْ جَآءَتْكَ ءَايَٰتِى فَكَذَّبْتَ بِهَا وَٱسْتَكْبَرْتَ وَكُنتَ مِنَ ٱلْكَٰفِرِينَ</font><font color=\"#008000\">﴿</font><font color=\"#008000\">٥٩</font><font color=\"#008000\">﴾</font><font color=\"#008000\">}</font><font color=\"#0000cd\"> صدق الله العظيم [الزمر].</font></font></span></div></span><span><div style=\"text-align: center;\">\n<span><font><font color=\"#0000cd\"><br>\r\nاللهم إنّك بنسيم عبد الهادي لعليمٌ وله ربٌّ غفورٌ رحيمٌ، فاهدهِ إلى الصراط المُستقيم، إنّك أنت السميعُ العليم إن كان من الذين لو علموا الحقّ من ربهم اتّبعوه وسلّموا تسليماً، إنّك بعبادك خبيرٌ بصيرٌ، اللهم إنك بعبادك أرحم من عبدك ووعدُك الحق وأنت أرحمُ الراحمين.<br>\r\n<br>\r\nوسلامٌ على المُرسلين، والحمدُ لله ربّ العالمين..<br>\r\nالإمام المهدي ناصر محمد اليماني.<br>\r\nــــــــــــــــــــ</font></font></span><br>\r\n</div></span>\n</div>\r\n\t\t\t\r\n\t\t\t\r\n\r\n\t\t\t\r\n\r\n\r\n\r\n\r\n<div class=\"pz-bottom\">\r\n<div class=\"pz-top-right\"></div>\r\n<div class=\"pz-top-center\"></div>\r\n<div class=\"pz-top-left\"></div>\r\n</div>",
